function e(e){if(!e)return``;let t=Date.now()-new Date(e).getTime(),n=Math.floor(t/6e4);if(n<1)return`только что`;if(n<60)return`${n} мин. назад`;let r=Math.floor(n/60);return r<24?`${r} ч. назад`:`${Math.floor(r/24)} дн. назад`}function t(e){if(!e)return``;let t=Date.now()-new Date(e).getTime(),n=Math.floor(t/6e4);if(n<1)return`сейчас`;if(n<60)return`${n} мин.`;let r=Math.floor(n/60);if(r<24)return`${r} ч.`;let i=Math.floor(r/24);return i===1?`вчера`:`${i} дн.`}export{t as n,e as t};